// Payout for one damage event: reimbursement less the per-event deductible.
const damagePayout = (item: Item, damage: Damage): number =>
  Math.max(0, reimbursement(item, damage.amount) - DEDUCTIBLE);

// The policy item a damage applies to, matched by type. A damage with no
// matching policy item is treated as a plain item (no enchantment clause).
const policyItemFor = (policy: Item[], damage: Damage): Item =>
  policy.find((item) => item.type === damage.itemType) ?? { type: damage.itemType };

// Payout for one damage within a policy: match the item, then compute its payout.
const damagePayoutInPolicy = (policy: Item[], damage: Damage): number =>
  damagePayout(policyItemFor(policy, damage), damage);

// Result of claiming against a policy: total payout (capped) and remaining cap.
const claimResult = (policy: Item[], incident: Incident): { payout: number; remainingCap: number } => {
  const cap = CAP_MULTIPLIER * sum(policy.map(insuranceValue));
  const payout = roundDownToWhole(
    sum(incident.damages.map((damage) => damagePayoutInPolicy(policy, damage))),
  );
  return { payout, remainingCap: cap - payout };
};
